var CONVERSATIONS_FR_AR = [
{ title: "Commander dans un café à Casablanca", scene: "Tu entres dans un café animé près du centre de Casablanca. Tu veux commander simplement un café et de l’eau.", lines: [{ who: "them", ar: "مرحبا، ماذا تريد؟", fr: "Bonjour, que voulez-vous ?" }, { who: "you", ar: "أريد قهوة من فضلك.", fr: "Je voudrais un café, s’il vous plaît." }, { who: "them", ar: "مع سكر؟", fr: "Avec du sucre ?" }, { who: "you", ar: "لا، بدون سكر من فضلك.", fr: "Non, sans sucre, s’il vous plaît." }, { who: "them", ar: "هل تريد ماء أيضا؟", fr: "Voulez-vous aussi de l’eau ?" }, { who: "you", ar: "نعم، ماء بارد من فضلك.", fr: "Oui, de l’eau froide, s’il vous plaît." }, { who: "them", ar: "تمام، شيء آخر؟", fr: "Parfait, autre chose ?" }, { who: "you", ar: "لا، شكرا.", fr: "Non, merci." }, { who: "them", ar: "القهوة والماء بخمسة عشر درهما.", fr: "Le café et l’eau coûtent quinze dirhams." }, { who: "you", ar: "تفضل، شكرا جزيلا.", fr: "Tenez, merci beaucoup." }] },
{ title: "Arriver à l’hôtel à Dubaï", scene: "Tu arrives à la réception d’un hôtel à Dubaï après un long vol. Tu veux faire l’enregistrement et demander le Wi-Fi.", lines: [{ who: "them", ar: "أهلا وسهلا، هل لديك حجز؟", fr: "Bienvenue, avez-vous une réservation ?" }, { who: "you", ar: "نعم، لدي حجز باسمي.", fr: "Oui, j’ai une réservation à mon nom." }, { who: "them", ar: "ما اسمك؟", fr: "Quel est votre nom ?" }, { who: "you", ar: "اسمي بول مارتان.", fr: "Je m’appelle Paul Martin." }, { who: "them", ar: "هل أرى جواز سفرك؟", fr: "Puis-je voir votre passeport ?" }, { who: "you", ar: "نعم، هذا جواز سفري.", fr: "Oui, voici mon passeport." }, { who: "them", ar: "غرفتك في الطابق الخامس.", fr: "Votre chambre est au cinquième étage." }, { who: "you", ar: "شكرا، أين المصعد؟", fr: "Merci, où est l’ascenseur ?" }, { who: "them", ar: "المصعد على اليمين.", fr: "L’ascenseur est à droite." }, { who: "you", ar: "وما كلمة سر الواي فاي؟", fr: "Et quel est le mot de passe du Wi-Fi ?" }, { who: "them", ar: "كلمة السر مكتوبة على البطاقة.", fr: "Le mot de passe est écrit sur la carte." }, { who: "you", ar: "شكرا جزيلا.", fr: "Merci beaucoup." }] },
{ title: "Demander son chemin à Amman", scene: "Tu es dans une rue d’Amman et tu cherches le musée. Tu demandes de l’aide à une personne locale.", lines: [{ who: "you", ar: "عفوا، أين المتحف؟", fr: "Pardon, où est le musée ?" }, { who: "them", ar: "المتحف قريب من هنا.", fr: "Le musée est proche d’ici." }, { who: "you", ar: "هل أذهب مستقيما؟", fr: "Est-ce que je vais tout droit ?" }, { who: "them", ar: "نعم، اذهب مستقيما ثم يمينا.", fr: "Oui, allez tout droit puis à droite." }, { who: "you", ar: "هل هو بجانب المسجد؟", fr: "Est-il à côté de la mosquée ?" }, { who: "them", ar: "نعم، بجانب المسجد الكبير.", fr: "Oui, à côté de la grande mosquée." }, { who: "you", ar: "كم دقيقة من هنا؟", fr: "Combien de minutes d’ici ?" }, { who: "them", ar: "حوالي عشر دقائق.", fr: "Environ dix minutes." }, { who: "you", ar: "شكرا على المساعدة.", fr: "Merci pour l’aide." }, { who: "them", ar: "عفوا، رحلة سعيدة.", fr: "De rien, bon voyage." }] },
{ title: "Dîner dans un restaurant à Rabat", scene: "Tu es dans un restaurant à Rabat et tu veux commander un plat simple. Tu vérifies aussi si le plat est épicé.", lines: [{ who: "them", ar: "مساء الخير، هل تريد القائمة؟", fr: "Bonsoir, voulez-vous le menu ?" }, { who: "you", ar: "نعم، من فضلك.", fr: "Oui, s’il vous plaît." }, { who: "them", ar: "تفضل، هذه القائمة.", fr: "Tenez, voici le menu." }, { who: "you", ar: "هل طبق الدجاج حار؟", fr: "Le plat de poulet est-il épicé ?" }, { who: "them", ar: "لا، هو خفيف.", fr: "Non, il est léger." }, { who: "you", ar: "جيد، أريد طبق الدجاج.", fr: "Bien, je voudrais le plat de poulet." }, { who: "them", ar: "هل تريد خبزا؟", fr: "Voulez-vous du pain ?" }, { who: "you", ar: "نعم، خبزا وماء من فضلك.", fr: "Oui, du pain et de l’eau, s’il vous plaît." }, { who: "them", ar: "شيء آخر؟", fr: "Autre chose ?" }, { who: "you", ar: "لا، شكرا.", fr: "Non, merci." }, { who: "them", ar: "الطعام سيأتي بعد قليل.", fr: "La nourriture arrivera dans un moment." }, { who: "you", ar: "شكرا جزيلا.", fr: "Merci beaucoup." }] },
{ title: "Acheter un billet de métro au Caire", scene: "Tu es à une station de métro au Caire. Tu veux acheter un billet et vérifier la bonne ligne.", lines: [{ who: "them", ar: "صباح الخير، إلى أين؟", fr: "Bonjour, pour où ?" }, { who: "you", ar: "أريد تذكرة إلى وسط المدينة.", fr: "Je voudrais un billet pour le centre-ville." }, { who: "them", ar: "تذكرة واحدة؟", fr: "Un billet ?" }, { who: "you", ar: "نعم، تذكرة واحدة من فضلك.", fr: "Oui, un billet, s’il vous plaît." }, { who: "them", ar: "السعر خمسة جنيهات.", fr: "Le prix est cinq livres." }, { who: "you", ar: "تفضل.", fr: "Tenez." }, { who: "them", ar: "هذه تذكرتك.", fr: "Voici votre billet." }, { who: "you", ar: "أي خط إلى وسط المدينة؟", fr: "Quelle ligne va au centre-ville ?" }, { who: "them", ar: "الخط الثاني، الاتجاه إلى اليمين.", fr: "La deuxième ligne, direction à droite." }, { who: "you", ar: "شكرا، هل المترو مزدحم؟", fr: "Merci, le métro est-il bondé ?" }, { who: "them", ar: "نعم، قليلا اليوم.", fr: "Oui, un peu aujourd’hui." }, { who: "you", ar: "شكرا على المساعدة.", fr: "Merci pour l’aide." }] },
{ title: "Acheter un cadeau dans un souk à Fès", scene: "Tu visites un souk à Fès et tu veux acheter un petit cadeau. Tu demandes le prix et cherches quelque chose de moins cher.", lines: [{ who: "them", ar: "أهلا، تفضل.", fr: "Bonjour, allez-y." }, { who: "you", ar: "شكرا، هذا جميل جدا.", fr: "Merci, c’est très beau." }, { who: "them", ar: "نعم، هذا مصنوع يدويا.", fr: "Oui, c’est fait à la main." }, { who: "you", ar: "كم سعر هذا؟", fr: "Combien coûte ceci ?" }, { who: "them", ar: "السعر مئة درهم.", fr: "Le prix est cent dirhams." }, { who: "you", ar: "هذا غالي قليلا.", fr: "C’est un peu cher." }, { who: "them", ar: "عندي شيء أرخص.", fr: "J’ai quelque chose de moins cher." }, { who: "you", ar: "أريد هدية صغيرة.", fr: "Je voudrais un petit cadeau." }, { who: "them", ar: "هذا بخمسين درهما.", fr: "Celui-ci coûte cinquante dirhams." }, { who: "you", ar: "جيد، سأشتريه.", fr: "Bien, je vais l’acheter." }, { who: "them", ar: "شكرا جزيلا.", fr: "Merci beaucoup." }, { who: "you", ar: "شكرا، مع السلامة.", fr: "Merci, au revoir." }] },
{ title: "À la pharmacie à Manama", scene: "Tu entres dans une pharmacie à Manama parce que tu as mal à la tête. Tu demandes un médicament simple.", lines: [{ who: "them", ar: "مرحبا، كيف أساعدك؟", fr: "Bonjour, comment puis-je vous aider ?" }, { who: "you", ar: "لدي ألم في الرأس.", fr: "J’ai mal à la tête." }, { who: "them", ar: "هل لديك حمى؟", fr: "Avez-vous de la fièvre ?" }, { who: "you", ar: "لا، فقط ألم في الرأس.", fr: "Non, seulement mal à la tête." }, { who: "them", ar: "هل لديك حساسية من دواء؟", fr: "Êtes-vous allergique à un médicament ?" }, { who: "you", ar: "لا، ليس لدي حساسية.", fr: "Non, je n’ai pas d’allergie." }, { who: "them", ar: "هذا الدواء مناسب.", fr: "Ce médicament convient." }, { who: "you", ar: "كم السعر؟", fr: "Quel est le prix ?" }, { who: "them", ar: "السعر ثلاثة دنانير.", fr: "Le prix est trois dinars." }, { who: "you", ar: "أريد إيصالا من فضلك.", fr: "Je voudrais un reçu, s’il vous plaît." }, { who: "them", ar: "تفضل، سلامتك.", fr: "Tenez, bon rétablissement." }, { who: "you", ar: "شكرا جزيلا.", fr: "Merci beaucoup." }] },
{ title: "Petite conversation avec une personne locale à Tanger", scene: "Tu es dans un café à Tanger et une personne locale commence à discuter avec toi. Tu réponds simplement et poliment.", lines: [{ who: "you", ar: "مرحبا، هل هذا المكان فارغ؟", fr: "Bonjour, cette place est-elle libre ?" }, { who: "them", ar: "نعم، تفضل.", fr: "Oui, allez-y." }, { who: "you", ar: "شكرا، اسمي بول.", fr: "Merci, je m’appelle Paul." }, { who: "them", ar: "أهلا بول، أنا يوسف.", fr: "Bonjour Paul, moi c’est Youssef." }, { who: "you", ar: "سعيد بلقائك يا يوسف.", fr: "Heureux de te rencontrer, Youssef." }, { who: "them", ar: "من أي بلد أنت؟", fr: "De quel pays viens-tu ?" }, { who: "you", ar: "أنا من فرنسا.", fr: "Je viens de France." }, { who: "them", ar: "هل تزور طنجة لأول مرة؟", fr: "Visites-tu Tanger pour la première fois ?" }, { who: "you", ar: "نعم، والمدينة جميلة جدا.", fr: "Oui, et la ville est très belle." }, { who: "them", ar: "ماذا ستفعل اليوم؟", fr: "Que vas-tu faire aujourd’hui ?" }, { who: "you", ar: "سأذهب إلى السوق ثم إلى الشاطئ.", fr: "Je vais aller au marché puis à la plage." }, { who: "them", ar: "خطة ممتازة، رحلة سعيدة.", fr: "Excellent plan, bon voyage." }] }
];
